import React, { useState, useRef } from "react";
import { Routes, Route, Navigate, useLocation } from "react-router-dom";
import Navbar from "./components/Navbar";
import Home from "./components/Home";
import About from "./components/About";
import PracticeAreas from "./components/PracticeAreas";
import Professionals from "./components/Professionals";
import News from "./components/News";
import Gallery from "./components/Gallery";
import Contact from "./components/Contact";
import AllNews from "./components/AllNews";
import Login from "./components/Login"; // Login component import
import AdminDashboard from "./components/AdminDashboard"; // AdminDashboard import
import "./styles.css";

function App() {
  const [auth, setAuth] = useState({
    isAuthenticated: false,
    user: null
  });

  const location = useLocation();  // Access the current route
  const newsSectionRef = useRef(null);

  const scrollToNewsSection = () => {
    if (newsSectionRef.current) {
      newsSectionRef.current.scrollIntoView({ behavior: "smooth" });
    }
  };

  return (
    <>
      {/* Only show Navbar if not on the /admin/login route */}
      {location.pathname !== "/admin/login" && (
        <Navbar auth={auth} setAuth={setAuth} />
      )}

      <Routes>
        {/* Static Routes */}
        <Route
          path="/"
          element={
            <>
              <section id="HOME">
                <Home />
              </section>
              <section id="ABOUT US">
                <About />
              </section>
              <section id="AREAS OF PRACTICE">
                <PracticeAreas />
              </section>
              <section id="OUR PROFESSIONALS">
                <Professionals />
              </section>
              <section id="NEWS & ARTICLES" ref={newsSectionRef}>
                <News />
              </section>
              <section id="GALLERY">
                <Gallery />
              </section>
              <section id="CONTACT US">
                <Contact />
              </section>
            </>
          }
        />

        {/* News Route */}
        <Route
          path="/news"
          element={
            <>
              <section id="HOME">
                <Home />
              </section>
              <section id="ABOUT US">
                <About />
              </section>
              <section id="AREAS OF PRACTICE">
                <PracticeAreas />
              </section>
              <section id="OUR PROFESSIONALS">
                <Professionals />
              </section>
              <section id="NEWS & ARTICLES" ref={newsSectionRef}>
                <News />
              </section>
              <section id="GALLERY">
                <Gallery />
              </section>
              <section id="CONTACT US">
                <Contact />
              </section>
            </>
          }
        />

        {/* More news section */}
        <Route
          path="/more-news"
          element={<AllNews scrollToNewsSection={scrollToNewsSection} />}
        />

        {/* Admin Login Route */}
        <Route
          path="/admin/login"
          element={
            auth.isAuthenticated ? (
              <Navigate to="/admin/dashboard" />
            ) : (
              <Login setAuth={setAuth} />
            )
          }
        />

        {/* Admin Dashboard Route */}
        <Route
          path="/admin/dashboard"
          element={
            auth.isAuthenticated ? (
              <AdminDashboard user={auth.user} />
            ) : (
              <Navigate to="/admin/login" />
            )
          }
        />

        {/* Admin Messages Route */}
        <Route
          path="/admin/messages"
          element={
            auth.isAuthenticated ? (
              <AdminDashboard user={auth.user} />
            ) : (
              <Navigate to="/admin/login" />
            )
          }
        />

        {/* 404 Route */}
        <Route path="*" element={<Navigate to="/" />} />
      </Routes>
    </>
  );
}

export default App;
